// // This module decrements the count on each clock cycle when enabled and sets it to maximum when reset is asserted.
module binary_counter (
    input wire clk,
    input wire rst,
    input wire en,
    output reg [3:0] count
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 4'b0000;
        end else if (en) begin
            count <= count + 1'b1;
        end
    end

endmodule
